INSERT INTO [Item Identifier] ( Code, [Item No_], [Variant Code], [Unit of Measure Code], [Unique identifier], [Assortment Variable Group], [Constant Assortment Var_Grp_], [Constant Variable Code], [Assortment Code], [Original Line No_], [Line Type], [No_ of Pairs], [Item Type], [Model Item No_], [Variable Group 01], [Variable Code 01], [Variable Group 02], [Variable Code 02], [Variable Group 03], [Variable Code 03], [Variable Group 04], [Variable Code 04], [Variable Group 05], [Variable Code 05], [Model Code], [Collection Code], [Season Code], [Line Code], [Original Line Type], [Brand Code], [Commercial Kit Code], Status, [Last Location Code Used], [Last Bin Code Used], [OutsourCing WMS] )
SELECT LogimodaColli.Collo, LogimodaColli.[Codice Articolo], "" AS Espr9, "PA" AS Espr1, 1 AS Espr2, LogimodaColli_AnagraficaItem.[Variable Group 02], LogimodaColli_AnagraficaItem.[Variable Group 01], LogimodaColli.Color_, LogimodaColli.Assortimento, 0 AS Espr3, 0 AS Espr4, LogimodaColli.quantita, 20 AS Espr5, "" AS Espr10, "" AS Espr11, "" AS Espr12, "" AS Espr13, "" AS Espr17, "" AS Espr14, "" AS Espr18, "" AS Espr15, "" AS Espr19, "" AS Espr16, "" AS Espr20, LogimodaColli_AnagraficaItem.[Model Code], LogimodaColli_AnagraficaItem.[Collection Code], LogimodaColli_AnagraficaItem.[Season Code], LogimodaColli_AnagraficaItem.[Line Code], 0 AS Espr6, LogimodaColli_AnagraficaItem.[Brand Code], "" AS Espr7, 0 AS Espr8, "" AS Espr21, "" AS Espr22, True AS Espr23
FROM LogimodaColli_AnagraficaItem RIGHT JOIN LogimodaColli ON (LogimodaColli_AnagraficaItem.[Model Item No_] = LogimodaColli.[Codice Articolo]) AND (LogimodaColli_AnagraficaItem.[Variable Code 01] = LogimodaColli.Color_)
WHERE (((LogimodaColli.InPrelievo)="N"));

